		return
	}

	writeJSON(w, http.StatusOK, map[string]string{
		"cwd": cwd,
	})
}

func (s *Server) workspaceForRequest(ctx context.Context) (session.Workspace, error) {
	if s.workspaceSource != nil {
		workspace, err := s.workspaceSource.Workspace(ctx)
		if err != nil {
