	return s.workspace, nil
}

func terminalSessionForRequest(workspace session.Workspace, projectID string, sessionID string) (session.Session, bool) {
	sessions := append([]session.Session{}, workspace.Sessions...)
	sessions = append(sessions, workspace.Orchestrators...)

	if projectID != "" {
		for _, terminalSession := range sessions {
			if terminalSession.Project == projectID && terminalSession.ID == sessionID {
				return terminalSession, true
			}
		}

		return session.Session{}, false
	}

	var found session.Session
	matches := 0
	for _, terminalSession := range sessions {
		if terminalSession.ID != sessionID {
			continue
		}
		found = terminalSession
		matches++
	}

	return found, matches == 1
}

func sessionWorkspaceDirectory(cwd string) (string, int, error) {
	cwd = strings.TrimSpace(cwd)
	if cwd == "" {
		return "", http.StatusUnprocessableEntity, errors.New("session workspace path is unavailable")
	}

	absolutePath, err := filepath.Abs(cwd)
	if err != nil {
		return "", http.StatusUnprocessableEntity, fmt.Errorf("resolve session workspace path: %w", err)
	}

	info, err := os.Stat(absolutePath)
	if err != nil {
		if errors.Is(err, os.ErrNotExist) {
			return "", http.StatusNotFound, fmt.Errorf("session workspace path does not exist: %s", absolutePath)
		}
		return "", http.StatusInternalServerError, fmt.Errorf("read session workspace path: %w", err)
	}
	if !info.IsDir() {
		return "", http.StatusUnprocessableEntity, fmt.Errorf("session workspace path is not a directory: %s", absolutePath)
	}

	return absolutePath, http.StatusOK, nil
}

