  }
  if (first === '--version' || first === '-v' || first === '-V') {
    return { kind: 'version' };
  }
  if (first === 'help') {
    if (rest.length > 1) {
      return {
        kind: 'usage-error',
        message: `Too many arguments for help: ${rest.slice(1).join(' ')}`,
      };
    }
    return { kind: 'help', commandName: rest[0] };
  }
  if (first.startsWith('-')) {
    return { kind: 'usage-error', message: `Unknown option: ${first}` };
  }

  if (implementedCommandNames.has(first)) {
    const helpArg = rest.find((arg) => arg === '--help' || arg === '-h');
    if (helpArg) {
      return { kind: 'help', commandName: first };
    }
    const unknownOption = rest.find((arg) => arg.startsWith('-'));
    if (unknownOption) {
      return {
        kind: 'usage-error',
        message: `Unknown option for ${first}: ${unknownOption}`,
      };
    }
    if (rest.length > 0) {
      return {
        kind: 'usage-error',
        message: `Unexpected argument for ${first}: ${rest[0]}`,
